(function(g){'use strict';class P{constructor(){this.pyodide=null;this.ready=false;this.q=[];this.loading=false;this.startTime=null;this.init()}async init(){if(this.loading)return;this.loading=true;this.startTime=Date.now();console.log('[PYTML] Initializing...');await this.waitForDOM();const s=this.createStatusIndicator();try{if(typeof loadPyodide==='undefined'){await this.loadScript('https://cdn.jsdelivr.net/pyodide/v0.24.1/full/pyodide.js')}if(s)s.textContent='[PYTML] Loading Python (6MB)...';this.pyodide=await loadPyodide({indexURL:'https://cdn.jsdelivr.net/pyodide/v0.24.1/full/',fullStdLib:false});await this.setupPythonEnvironment();this.ready=true;const t=((Date.now()-this.startTime)/1e3).toFixed(1);console.log(`[PYTML] Ready in ${t}s`);if(s&&s.parentNode)s.style.display='none';this.q.forEach(c=>c());this.q=[];this.processPage()}catch(e){console.error('[PYTML] Failed:',e);if(s){s.textContent='[PYTML] Failed to load';s.style.background='#dc3545'}}}waitForDOM(){return new Promise(r=>{if(document.readyState!=='loading')r();else document.addEventListener('DOMContentLoaded',r)})}createStatusIndicator(){let d=document.getElementById('pytml-status');if(d)return d;d=document.createElement('div');d.id='pytml-status';d.style.cssText='position:fixed;bottom:10px;right:10px;background:#007acc;color:#fff;padding:8px 12px;border-radius:4px;font-size:12px;font-family:monospace;z-index:9999;box-shadow:0 2px 5px rgba(0,0,0,0.2)';d.textContent='[PYTML] Loading Python...';if(document.body){document.body.appendChild(d)}else{document.addEventListener('DOMContentLoaded',()=>{if(document.body&&!document.getElementById('pytml-status')){document.body.appendChild(d)}})}return d}loadScript(s){return new Promise((r,j)=>{const t=document.createElement('script');t.src=s;t.onload=r;t.onerror=()=>j(new Error(`Failed to load ${s}`));document.head.appendChild(t)})}async setupPythonEnvironment(){if(!this.pyodide)return;await this.pyodide.runPythonAsync(`import sys,io,re
class C:
    def __init__(s):s.b=[]
    def write(s,t):s.b.append(t)
    def get(s):return''.join(s.b)
    def clear(s):s.b=[]
o=sys.stdout
c=C()
def n(c):
    l=c.split('\\n')
    if not l:return c
    b=None
    for x in l:
        s=x.strip()
        if s and not s.startswith('#'):
            m=re.match(r'^\\s+',x)
            if m:b=len(m.group())
            else:b=0
            break
    if b is None:return c
    r=[]
    for x in l:
        if x.strip():
            s=x.lstrip()
            if b>0:r.append('    '+s)
            else:r.append(s)
        else:r.append('')
    return '\\n'.join(r)
def e(code,inp):
    c.clear()
    sys.stdout=c
    try:
        code=n(code)
        for k,v in inp.items():globals()[k]=v
        exec(code)
        r=c.get()
        sys.stdout=o
        return{'success':True,'output':r}
    except Exception as ex:
        sys.stdout=o
        return{'success':False,'error':str(ex)}`)}async wait(){if(this.ready)return;return new Promise(r=>this.q.push(r))}async run(c,s={}){if(!this.ready)await this.wait();try{const i=JSON.stringify(s);const r=await this.pyodide.runPythonAsync(`r=e(${JSON.stringify(c)},${i});r`);if(r.toJs&&typeof r.toJs==='function'){const j=r.toJs();if(!j.success)throw new Error(j.error);return j.output}if(r.success===false)throw new Error(r.error);return r.output||''}catch(e){return`Error: ${e.message}`}}async processPage(){if(!this.ready)return;const e=document.querySelectorAll('[data-python],[data-python-text],[data-python-html]');console.log(`[PYTML] Found ${e.length} Python elements`);for(const el of e){await this.bindElement(el)}}async bindElement(el){if(!el)return;if(el.hasAttribute('data-python-text')){const c=el.getAttribute('data-python-text');const r=await this.run(c);if(el)el.textContent=r}if(el.hasAttribute('data-python-html')){const c=el.getAttribute('data-python-html');const r=await this.run(c);if(el)el.innerHTML=r}if(el.hasAttribute('data-python')){const c=el.getAttribute('data-python');const t=el.getAttribute('data-event')||'click';const ts=el.getAttribute('data-target');const h=async()=>{try{const i=this.collectInputs(el);const r=await this.run(c,i);if(ts){const tg=document.querySelector(ts);if(tg){tg.innerHTML=r.replace(/\n/g,'<br>')}}}catch(e){if(ts){const tg=document.querySelector(ts);if(tg){tg.innerHTML=`Error: ${e.message}`}}}};el.addEventListener(t,h)}}collectInputs(el){const i={};const f=el.closest('[data-python-form]');if(f){const a=f.querySelectorAll('input, select, textarea');for(const inp of a){if(inp.name){let v=inp.value;if(inp.type==='number'){v=parseFloat(v)}else if(inp.type==='checkbox'){v=inp.checked}i[inp.name]=v}}}return i}getStatus(){return{ready:this.ready,loadingTime:this.startTime?((Date.now()-this.startTime)/1e3).toFixed(1):null}}}const p=new P;g.pytml=p})(window);
